1	type Item = { type: string; enchantment?: number; cursed?: boolean; material?: string };
2	type QuoteStep = { op: "quote"; items: Item[] };
3	type Damage = { itemType: string; amount: number };
4	type Incident = { cause: string; damages: Damage[] };
5	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
6	type Step = QuoteStep | ClaimStep;
7	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
8	type QuoteResult = { premium: number };
9	type ClaimResult = { payout: number; remainingCap: number };
10	type StepResult = QuoteResult | ClaimResult;
11	
12	const PROCESSING_FEE = 5;
13	const FIRST_INSURANCE_SURCHARGE_PERCENT = 10;
14	const THREE_ALIKE_BLOCK_PREMIUM = 60;
15	
16	type ItemTypeSpec = { basePremium: number; insuranceValue: number; isComponent: boolean };
17	
18	const ITEM_TYPES: Record<string, ItemTypeSpec> = {
19	  // Whole items
20	  sword: { basePremium: 100, insuranceValue: 1000, isComponent: false },
21	  amulet: { basePremium: 60, insuranceValue: 600, isComponent: false },
22	  staff: { basePremium: 80, insuranceValue: 800, isComponent: false },
23	  potion: { basePremium: 40, insuranceValue: 400, isComponent: false },
24	  // Components (eligible for 3-alike block premium)
25	  rune: { basePremium: 25, insuranceValue: 250, isComponent: true },
26	  moonstone: { basePremium: 25, insuranceValue: 250, isComponent: true },
27	};
28	
29	const percentOf = (amount: number, percent: number): number => (amount * percent) / 100;
30	
31	const countBy = <T>(items: T[], keyOf: (item: T) => string): Map<string, number> =>
32	  items.reduce(
33	    (counts, item) => counts.set(keyOf(item), (counts.get(keyOf(item)) ?? 0) + 1),
34	    new Map<string, number>(),
35	  );
36	
37	const countByType = (items: Item[]): Map<string, number> =>
38	  countBy(items, (item) => item.type);
39	
40	const basePremiumForGroup = (type: string, count: number): number => {
41	  const spec = ITEM_TYPES[type];
42	  if (spec.isComponent && count === 3) return THREE_ALIKE_BLOCK_PREMIUM;
43	  return count * spec.basePremium;
44	};
45	
46	const HIGH_ENCHANTMENT_SURCHARGE_PERCENT = 30;
47	const HIGH_ENCHANTMENT_THRESHOLD = 5;
48	const CURSE_SURCHARGE_PERCENT = 50;
49	
50	// Each surcharge rule receives the item and its base premium and returns
51	// the surcharge amount in gold (0 when the rule does not apply).
52	type ItemSurchargeRule = (item: Item, itemBase: number) => number;
53	
54	const ITEM_SURCHARGE_RULES: ItemSurchargeRule[] = [
55	  (item, itemBase) =>
56	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
57	      ? percentOf(itemBase, HIGH_ENCHANTMENT_SURCHARGE_PERCENT)
58	      : 0,
59	  (item, itemBase) =>
60	    item.cursed ? percentOf(itemBase, CURSE_SURCHARGE_PERCENT) : 0,
61	];
62	
63	const itemSurcharges = (item: Item): number => {
64	  const itemBase = ITEM_TYPES[item.type].basePremium;
65	  return ITEM_SURCHARGE_RULES.reduce((sum, rule) => sum + rule(item, itemBase), 0);
66	};
67	
68	const sumBy = <T>(items: T[], valueOf: (item: T) => number): number =>
69	  items.reduce((sum, item) => sum + valueOf(item), 0);
70	
71	const policyBasePremium = (items: Item[]): number =>
72	  sumBy(
73	    [...countByType(items)],
74	    ([type, count]) => basePremiumForGroup(type, count),
75	  );
76	
77	const itemSurchargesTotal = (items: Item[]): number => sumBy(items, itemSurcharges);
78	
79	const LOYALTY_DISCOUNT_PERCENT = 20;
80	const LOYALTY_MIN_YEARS = 2;
81	const FOLLOWUP_CONTRACT_DISCOUNT_PERCENT = 15;
82	
83	// Each policy adjustment receives the base premium and quote context and
84	// returns a signed amount in gold: positive for surcharges, negative for
85	// discounts, 0 when the rule does not apply.
86	type QuoteContext = { yearsWithMHPCO: number; priorQuoteCount: number };
87	type PolicyAdjustmentRule = (basePremium: number, context: QuoteContext) => number;
88	
89	const POLICY_ADJUSTMENT_RULES: PolicyAdjustmentRule[] = [
90	  (basePremium) => percentOf(basePremium, FIRST_INSURANCE_SURCHARGE_PERCENT),
91	  (basePremium, { yearsWithMHPCO }) =>
92	    yearsWithMHPCO >= LOYALTY_MIN_YEARS ? -percentOf(basePremium, LOYALTY_DISCOUNT_PERCENT) : 0,
93	  (basePremium, { priorQuoteCount }) =>
94	    priorQuoteCount > 0 ? -percentOf(basePremium, FOLLOWUP_CONTRACT_DISCOUNT_PERCENT) : 0,
95	];
96	
97	const policyAdjustmentsTotal = (basePremium: number, context: QuoteContext): number =>
98	  sumBy(POLICY_ADJUSTMENT_RULES, (rule) => rule(basePremium, context));
99	
100	const quotePremium = (items: Item[], context: QuoteContext): number => {
101	  const base = policyBasePremium(items);
102	  const beforeFee = base + policyAdjustmentsTotal(base, context) + itemSurchargesTotal(items);
103	  return Math.ceil(beforeFee) + PROCESSING_FEE;
104	};
105	
106	const DEDUCTIBLE_PER_DAMAGE = 100;
107	const CAP_MULTIPLIER = 2;
108	
109	const insuranceSum = (items: Item[]): number =>
110	  sumBy(items, (item) => ITEM_TYPES[item.type].insuranceValue);
111	
112	const policyCap = (items: Item[]): number => insuranceSum(items) * CAP_MULTIPLIER;
113	
114	type Policy = { items: Item[]; remainingCap: number };
115	
116	const VERY_HIGH_ENCHANTMENT_THRESHOLD = 8;
117	const VERY_HIGH_ENCHANTMENT_REIMBURSEMENT_PERCENT = 50;
118	
119	const insuredItem = (policy: Policy, itemType: string): Item =>
120	  policy.items.find((item) => item.type === itemType)!;
121	
122	const reimbursableAmount = (item: Item, damageAmount: number): number =>
123	  (item.enchantment ?? 0) >= VERY_HIGH_ENCHANTMENT_THRESHOLD
124	    ? percentOf(damageAmount, VERY_HIGH_ENCHANTMENT_REIMBURSEMENT_PERCENT)
125	    : damageAmount;
126	
127	const damagePayout = (damage: Damage, policy: Policy): number => {
128	  const item = insuredItem(policy, damage.itemType);
129	  return Math.max(0, reimbursableAmount(item, damage.amount) - DEDUCTIBLE_PER_DAMAGE);
130	};
131	
132	const validateDamages = (policy: Policy, damages: Damage[]): void => {
133	  const insuredCounts = countByType(policy.items);
134	  const damageCounts = countBy(damages, (damage) => damage.itemType);
135	  for (const [type, count] of damageCounts) {
136	    const insured = insuredCounts.get(type) ?? 0;
137	    if (count > insured) {
138	      throw new Error(`Damage references ${count} ${type} entries but policy insures only ${insured}`);
139	    }
140	  }
141	};
142	
143	const processClaim = (policy: Policy, incident: Incident): ClaimResult => {
144	  validateDamages(policy, incident.damages);
145	  const rawPayout = sumBy(incident.damages, (damage) => damagePayout(damage, policy));
146	  const payout = Math.min(rawPayout, policy.remainingCap);
147	  policy.remainingCap -= payout;
148	  return { payout: Math.floor(payout), remainingCap: policy.remainingCap };
149	};
150	
151	const validateItemTypes = (items: Item[]): void => {
152	  for (const item of items) {
153	    if (!(item.type in ITEM_TYPES)) {
154	      throw new Error(`Unknown item type: ${item.type}`);
155	    }
156	  }
157	};
158	
159	export const runScenario = (scenario: Scenario): { results: StepResult[] } => {
160	  const { yearsWithMHPCO } = scenario.customer;
161	  const policies: Policy[] = [];
162	  const results: StepResult[] = scenario.steps.map((step) => {
163	    if (step.op === "quote") {
164	      validateItemTypes(step.items);
165	      const premium = quotePremium(step.items, {
166	        yearsWithMHPCO,
167	        priorQuoteCount: policies.length,
168	      });
169	      policies.push({ items: step.items, remainingCap: policyCap(step.items) });
170	      return { premium };
171	    }
172	    return processClaim(policies[step.policy], step.incident);
173	  });
174	  return { results };
175	};
